import { useParams, Link } from "react-router-dom";
import Card from "../components/Card";

const resources = {
  "AI-&-ML": [
    { name: "Coursera ML", url: "https://www.coursera.org/learn/machine-learning" },
    { name: "Kaggle Learn", url: "https://www.kaggle.com/learn" },
    { name: "Google ML Crash Course", url: "https://developers.google.com/machine-learning/crash-course" },
    { name: "Fast.ai", url: "https://www.fast.ai/" }
  ],

  "Web-Development": [
    { name: "MDN Docs", url: "https://developer.mozilla.org" },
    { name: "FreeCodeCamp", url: "https://www.freecodecamp.org" },
    { name: "W3Schools", url: "https://www.w3schools.com" },
    { name: "Frontend Masters", url: "https://frontendmasters.com" }
  ],

  "Cloud-&-DevOps": [
    { name: "AWS Training", url: "https://aws.amazon.com/training/" },
    { name: "Azure Learn", url: "https://learn.microsoft.com/en-us/training/" },
    { name: "Google Cloud Skills Boost", url: "https://cloud.google.com/training" },
    { name: "Docker Docs", url: "https://docs.docker.com" }
  ],

  "Cybersecurity": [
    { name: "Cybrary", url: "https://www.cybrary.it/" },
    { name: "TryHackMe", url: "https://tryhackme.com/" },
    { name: "Hack The Box", url: "https://www.hackthebox.com/" },
    { name: "OWASP", url: "https://owasp.org/" }
  ],

  "Data-Science": [
    { name: "Kaggle", url: "https://www.kaggle.com/" },
    { name: "DataCamp", url: "https://www.datacamp.com/" },
    { name: "Coursera Data Science", url: "https://www.coursera.org/specializations/jhu-data-science" }
  ],

  "Mobile-Development": [
    { name: "Android Developers", url: "https://developer.android.com" },
    { name: "React Native Docs", url: "https://reactnative.dev" },
    { name: "Flutter Docs", url: "https://flutter.dev" }
  ],

  "Blockchain": [
    { name: "Ethereum Docs", url: "https://ethereum.org/en/developers/" },
    { name: "CryptoZombies", url: "https://cryptozombies.io/" },
    { name: "Solidity Docs", url: "https://docs.soliditylang.org/" }
  ],

  "IoT": [
    { name: "Arduino", url: "https://www.arduino.cc/" },
    { name: "Raspberry Pi", url: "https://www.raspberrypi.org/" },
    { name: "IoT For Beginners (Microsoft)", url: "https://github.com/microsoft/IoT-For-Beginners" }
  ],

  "Game-Development": [
    { name: "Unity Learn", url: "https://learn.unity.com/" },
    { name: "Unreal Engine Docs", url: "https://docs.unrealengine.com/" },
    { name: "Godot Engine", url: "https://godotengine.org/" }
  ],

  "AR/VR": [
    { name: "Unity XR", url: "https://unity.com/xr" },
    { name: "WebXR", url: "https://immersiveweb.dev/" },
    { name: "Oculus Dev", url: "https://developer.oculus.com/" }
  ],

  "Big-Data": [
    { name: "Hadoop", url: "https://hadoop.apache.org/" },
    { name: "Spark Docs", url: "https://spark.apache.org/docs/latest/" },
    { name: "Google BigQuery", url: "https://cloud.google.com/bigquery" }
  ],

  "Quantum-Computing": [
    { name: "IBM Quantum", url: "https://quantum-computing.ibm.com/" },
    { name: "Qiskit", url: "https://qiskit.org/" }
  ],

  "Robotics": [
    { name: "ROS", url: "https://www.ros.org/" },
    { name: "MIT Robotics", url: "https://robotics.mit.edu/" }
  ],

  "Natural-Language-Processing": [
    { name: "Hugging Face", url: "https://huggingface.co/" },
    { name: "NLTK", url: "https://www.nltk.org/" },
    { name: "SpaCy", url: "https://spacy.io/" }
  ],

  "Computer-Vision": [
    { name: "OpenCV", url: "https://opencv.org/" },
    { name: "PyTorch Vision", url: "https://pytorch.org/vision/stable/index.html" }
  ],

  "Embedded-Systems": [
    { name: "Embedded C", url: "https://www.geeksforgeeks.org/embedded-c/" },
    { name: "ARM Docs", url: "https://developer.arm.com/" }
  ],

  "Network-Engineering": [
    { name: "Cisco Networking Academy", url: "https://www.netacad.com/" },
    { name: "CompTIA Network+", url: "https://www.comptia.org/" }
  ],

  "Database-Administration": [
    { name: "MySQL Docs", url: "https://dev.mysql.com/doc/" },
    { name: "PostgreSQL", url: "https://www.postgresql.org/docs/" }
  ],

  "Software-Testing": [
    { name: "Selenium", url: "https://www.selenium.dev/" },
    { name: "Test Automation University", url: "https://testautomationu.applitools.com/" }
  ],

  "UI/UX-Design": [
    { name: "Figma", url: "https://www.figma.com/" },
    { name: "UX Design CC", url: "https://uxdesign.cc/" }
  ]
};

export default function DomainDetailPage() {
  const { name } = useParams();
  const links = resources[name] || [];

  return (
    <div className="space-y-8">
      
      <Card
        title={`${name.replace(/-/g, " ")} Resources`}
        description="Explore curated learning resources for this domain."
      >
        
        {/* Back Button */}
        <div className="mb-6">
          <Link
            to="/domains"
            className="text-sm text-blue-600 underline"
          >
            ← Back to Domains
          </Link>
        </div>

        {/* Links Grid */}
        <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
          {links.map((link, index) => (
            <a
              key={index}
              href={link.url}
              target="_blank"
              rel="noreferrer"
              className="rounded-[2rem] border border-slate-300 bg-gradient-to-br from-green-100 to-emerald-100 p-6 shadow-md hover:shadow-lg transition dark:border-slate-600 dark:from-slate-700 dark:to-slate-700 dark:shadow-slate-950/50"
            >
              <h3 className="text-lg font-semibold text-slate-900 dark:text-slate-50">
                {link.name}
              </h3>
              <p className="mt-2 text-sm text-slate-700 dark:text-slate-300">
                Click to open resource
              </p>
            </a>
          ))}
        </div>

        {/* Empty State */}
        {links.length === 0 && (
          <p className="text-slate-600 dark:text-slate-300">
            No resources available yet.
          </p>
        )}

      </Card>
    </div>
  );
}
